const attrs = msg.data.new_state.attributes || {};
const entityId = msg.data.entity_id;
const mediaTitle = (attrs.media_title || "").trim();
const sender = (attrs.media_artist || "").trim();

// Muss Doppelpunkt enthalten ("Artist: Titel")
if (!mediaTitle || !mediaTitle.includes(":")) {
    node.status({fill:"grey", shape:"ring", text:"Kein Song: " + mediaTitle});
    return null;
}

// Artist und Titel aus media_title parsen
const colonIdx = mediaTitle.indexOf(":");
const artist = mediaTitle.substring(0, colonIdx).trim();
const title = mediaTitle.substring(colonIdx + 1).trim();

if (!artist || !title) {
    node.status({fill:"grey", shape:"ring", text:"Leer: " + mediaTitle});
    return null;
}

const titleLower = title.toLowerCase();
const artistLower = artist.toLowerCase();

// Kein-Song-Filter: Programmhinweise, E-Mails, URLs, Telefonnummern
const noSongPatterns = [
    /^(e-?mail|telefon|tel|fax|sms|whatsapp|web|www|http|studio|redaktion|hotline)$/i,
    /@/,
    /^\d+$/,
    /\.de$|\.com$|\.org$/i,
    /^\+?\d[\d\s\-\/]{6,}$/
];
for (const pat of noSongPatterns) {
    if (pat.test(artist) || pat.test(title)) {
        node.status({fill:"grey", shape:"ring", text:"Kein Song: " + mediaTitle});
        return null;
    }
}

// Senderfilter
const senderFilter = [
    "bayern 1", "br1", "bayern 3", "br3",
    "klassik radio", "klassik radio movie",
    "ndr 2", "ndr2", "swr3", "wdr 2", "wdr2",
    "antenne bayern", "nachrichten",
    "verkehr", "wetter", "werbung"
];
for (const s of senderFilter) {
    if (artistLower === s || titleLower === s) {
        node.status({fill:"grey", shape:"ring", text:"Sender: " + mediaTitle});
        return null;
    }
}

// Artist == Title
if (titleLower === artistLower) {
    node.status({fill:"grey", shape:"ring", text:"Artist=Title: " + mediaTitle});
    return null;
}

// Duplikat-Filter (pro Alexa getrennt)
const lastKey = flow.get('last_song_' + entityId) || "";
const currentKey = artist + " - " + title;
if (currentKey === lastKey) {
    node.status({fill:"grey", shape:"dot", text:"Duplikat: " + currentKey});
    return null;
}

flow.set('last_song_' + entityId, currentKey);

msg.song = {
    artist: artist,
    title: title,
    source: sender || "Unbekannt",
    entity_id: entityId
};

node.status({fill:"green", shape:"dot", text: entityId.split('.')[1].substring(0,10) + ": " + currentKey});
return msg;

const title = encodeURIComponent(msg.song.title);
const artist = encodeURIComponent(msg.song.artist);
msg.url = `https://musicbrainz.org/ws/2/recording/?query=recording:"${title}"+AND+artist:"${artist}"&fmt=json&limit=1`;
node.status({fill:"yellow", shape:"ring", text:"Suche: " + msg.song.artist + " - " + msg.song.title});
return msg;

let year = "?";

try {
    const recordings = msg.payload.recordings || [];
    if (recordings.length > 0) {
        const rec = recordings[0];
        const dateStr = rec["first-release-date"] || "";
        if (dateStr.length >= 4) {
            year = dateStr.substring(0, 4);
        }
    }
} catch(e) {
    node.warn("MusicBrainz Parse-Fehler: " + e.message);
}

const now = new Date().toISOString();

msg.payload = {
    artist: msg.song.artist,
    title: msg.song.title,
    year: year,
    source: msg.song.source,
    entity_id: msg.song.entity_id,
    timestamp: now
};

const display = msg.song.artist + " - " + msg.song.title + " (" + year + ")";
node.status({fill: year !== "?" ? "blue" : "red", shape:"dot", text: display});
return msg;

// Mapping: Alexa Entity -> Toggle
const alexaToggleMap = {
    "media_player.marcus_echo_show_8_2nd_gen": "input_boolean.song_info_echo_show",
    "media_player.marcus_echo_dot": "input_boolean.song_info_echo_dot",
    "media_player.marcus_echo_plus": "input_boolean.song_info_echo_plus"
};

const p = msg.payload;
const sourceEntity = p.entity_id;
const message = p.artist + " - " + p.title + " (" + p.year + ")";

// Sammle alle Alexas deren Toggle an ist
const targets = [];
for (const [alexa, toggle] of Object.entries(alexaToggleMap)) {
    const state = global.get('homeassistant.homeAssistant.states["' + toggle + '"].state');
    if (state === "on") {
        targets.push(alexa);
    }
}

if (targets.length === 0) {
    node.status({fill:"grey", shape:"ring", text:"Keine Alexa aktiv"});
    return null;
}

msg.announce = {
    message: message,
    targets: targets,
    data: { type: "announce", method: "all" }
};

node.status({fill:"green", shape:"dot", text: targets.length + "x: " + message});
return msg;
